-- ============================================
-- Views for Streamlit Dashboard
-- ============================================

CREATE OR REPLACE VIEW vw_total_revenue AS
SELECT COALESCE(SUM(total_amount), 0) AS total_revenue FROM fact_sales;

CREATE OR REPLACE VIEW vw_category_revenue AS
SELECT p.category, COALESCE(SUM(s.total_amount), 0) AS revenue
FROM dim_products p
LEFT JOIN fact_sales s ON p.product_id = s.product_id
GROUP BY p.category;

CREATE OR REPLACE VIEW vw_category_product_drilldown AS
SELECT 
    p.category, 
    p.product_name, 
    COALESCE(SUM(s.quantity), 0) AS units_sold, 
    COALESCE(SUM(s.total_amount), 0) AS revenue,
    COUNT(s.sale_id) AS orders,
    CASE WHEN COUNT(s.sale_id) > 0 THEN SUM(s.total_amount) / COUNT(s.sale_id) ELSE 0 END AS avg_order_value
FROM dim_products p
LEFT JOIN fact_sales s ON p.product_id = s.product_id
GROUP BY p.category, p.product_name;

CREATE OR REPLACE VIEW vw_monthly_trend AS
SELECT TO_CHAR(sale_date, 'YYYY-MM') AS month, SUM(total_amount) AS monthly_revenue
FROM fact_sales
GROUP BY TO_CHAR(sale_date, 'YYYY-MM');

CREATE OR REPLACE VIEW vw_monthly_daily_drilldown AS
SELECT 
    TO_CHAR(sale_date, 'YYYY-MM') AS month,
    CAST(sale_date AS DATE) AS sale_day,
    SUM(total_amount) AS daily_revenue,

    COUNT(sale_id) AS orders
FROM fact_sales
GROUP BY TO_CHAR(sale_date, 'YYYY-MM'), CAST(sale_date AS DATE);

CREATE OR REPLACE VIEW vw_top_customers AS
SELECT c.first_name || ' ' || c.last_name AS customer_name, SUM(s.total_amount) AS total_spent
FROM dim_customers c
JOIN fact_sales s ON c.customer_id = s.customer_id
GROUP BY c.customer_id, c.first_name, c.last_name
ORDER BY total_spent DESC
LIMIT 5;

CREATE OR REPLACE VIEW vw_customer_orders_drilldown AS
SELECT 
    c.first_name || ' ' || c.last_name AS customer_name,
    p.product_name,
    p.category,
    s.sale_date,
    s.quantity,
    s.total_amount
FROM fact_sales s
JOIN dim_customers c ON s.customer_id = c.customer_id
JOIN dim_products p ON s.product_id = p.product_id;

CREATE OR REPLACE VIEW vw_top_products AS
SELECT p.product_name, p.category, SUM(s.quantity) AS units_sold, SUM(s.total_amount) AS revenue
FROM dim_products p
JOIN fact_sales s ON p.product_id = s.product_id
GROUP BY p.product_id, p.product_name, p.category
ORDER BY revenue DESC
LIMIT 5;
